<?php
if ( ! defined( 'ABSPATH' ) ) { exit; }
class VH360_Studio_Bible_Admin {
    public function __construct(){add_action('admin_menu',array($this,'menu'));add_action('admin_enqueue_scripts',array($this,'assets'));}
    public function menu(){add_submenu_page('options-general.php',__('VH360 Bible Library','videohub360-studio'),__('VH360 Bible Library','videohub360-studio'),'manage_options','vh360-studio-bible',array($this,'render'));}
    public function assets($hook){if(false===strpos($hook,'vh360-studio-bible'))return;$p='assets/admin/studio-bible-admin.js';wp_enqueue_script('vh360-studio-bible-admin',VH360_STUDIO_PLUGIN_URL.$p,array(),VH360_STUDIO_VERSION.'-'.filemtime(VH360_STUDIO_PLUGIN_DIR.$p),true);wp_localize_script('vh360-studio-bible-admin','vh360StudioBibleAdmin',array('restRoot'=>esc_url_raw(rest_url('vh360-studio/v1')),'nonce'=>wp_create_nonce('wp_rest')));}
    public function render(){ $repo=new VH360_Studio_Bible_Repository(); echo '<div class="wrap"><h1>'.esc_html__('Bible Library','videohub360-studio').'</h1><table class="widefat"><thead><tr><th>Translation</th><th>Abbreviation</th><th>Language</th><th>Books</th><th>Verses</th><th>Dataset</th><th>Source</th><th>License</th></tr></thead><tbody>'; foreach($repo->list_translations() as $tr){echo '<tr><td>'.esc_html($tr['name']).'</td><td>'.esc_html($tr['abbreviation']).'</td><td>'.esc_html($tr['language']).'</td><td>'.esc_html($tr['bookCount']).'</td><td>'.esc_html($tr['verseCount']).'</td><td>'.esc_html($tr['datasetVersion']).'</td><td>'.esc_html($tr['sourceName']).'</td><td>'.esc_html($tr['licenseName']).'</td></tr>';} echo '</tbody></table><h2>'.esc_html__('Import translation','videohub360-studio').'</h2><form id="vh360-bible-import-form" enctype="multipart/form-data"><input type="file" name="file" accept=".csv,text/csv" required><input name="translationKey" placeholder="kjv" required><input name="name" placeholder="Full translation name" required><input name="abbreviation" placeholder="KJV" required><input name="language" placeholder="en" required><input name="sourceName" placeholder="Dataset source" required><input name="sourceUrl" placeholder="Source URL"><input name="licenseName" placeholder="License name" required><input name="licenseUrl" placeholder="License URL"><textarea name="attribution" placeholder="Attribution"></textarea><input name="datasetVersion" placeholder="Dataset version" required><label><input type="checkbox" name="permissionConfirmed" value="1" required> '.esc_html__('I confirm permission to use this file.','videohub360-studio').'</label><button class="button button-primary">'.esc_html__('Import translation','videohub360-studio').'</button></form><pre id="vh360-bible-import-progress"></pre></div>';}
}
